import React, { useEffect, useState } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentSong, setCurrentSong] = useState(null);

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) {
                console.error("Lỗi lấy danh sách nhạc:", err);
            }
        };
        fetchSongs();
    }, []);

    return (
        <div style={{ padding: '20px', maxWidth: '900px', margin: '0 auto', paddingBottom: '120px' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '30px', color: '#333' }}>DANH SÁCH BÀI HÁT</h2>
            
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {songs.length === 0 ? (
                    <p style={{ textAlign: 'center', color: '#888' }}>Chưa có bài hát nào.</p>
                ) : (
                    songs.map((song) => (
                        <div key={song._id} style={{
                            display: 'flex', 
                            alignItems: 'center', 
                            padding: '12px 20px', 
                            border: '1px solid #eee', 
                            borderRadius: '12px',
                            background: currentSong?._id === song._id ? '#f0f7ff' : '#fff',
                            transition: 'all 0.3s ease',
                            boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
                        }}>
                            {/* Ảnh bìa */}
                            <img 
                                src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/60'} 
                                alt="cover" 
                                style={{ width: '60px', height: '60px', borderRadius: '8px', marginRight: '20px', objectFit: 'cover' }}
                            />
                            
                            {/* Thông tin bài hát - Dùng flex: 1 để đẩy nút Play sang phải */}
                            <div style={{ flex: 1, minWidth: 0 }}>
                                <div style={{ fontWeight: 'bold', fontSize: '18px', marginBottom: '4px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                    {song.title}
                                </div>
                                <div style={{ fontSize: '14px', color: '#666' }}>{song.artist}</div>
                            </div>

                            {/* Nút Play */}
                            <button 
                                onClick={() => setCurrentSong(song)}
                                style={{ 
                                    padding: '10px 25px', 
                                    cursor: 'pointer', 
                                    background: '#28a745', 
                                    color: '#fff', 
                                    border: 'none', 
                                    borderRadius: '25px',
                                    fontWeight: 'bold',
                                    marginLeft: '15px'
                                }}
                            >
                                PLAY
                            </button>
                        </div>
                    ))
                )}
            </div>

            {/* Trình phát nhạc cố định ở dưới chân trang */}
            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#222', color: '#fff', padding: '20px', 
                    boxShadow: '0 -5px 15px rgba(0,0,0,0.3)',
                    display: 'flex', flexDirection: 'column', alignItems: 'center',
                    zIndex: 1000
                }}>
                    <div style={{ marginBottom: '10px', fontSize: '16px' }}>
                        Đang phát: <span style={{ color: '#28a745', fontWeight: 'bold' }}>{currentSong.title}</span> - {currentSong.artist}
                    </div>
                    <audio 
                        src={`http://localhost:5000${currentSong.songUrl}`} 
                        controls 
                        autoPlay 
                        style={{ width: '100%', maxWidth: '800px' }}
                    />
                </div>
            )}
        </div>
    );
};

export default Home;
